-- Matthew Chapter 22 — The King Silences His Adversaries
-- Wedding Feast Parable, Tribute, Resurrection, Great Commandment, David's Lord

-- =====================================================================
-- 1. CHAPTER METADATA
-- =====================================================================
INSERT INTO chapters (book_id, chapter_number, overview, theme, key_word_original, key_word_meaning, outline)
SELECT b.id, 22,
  'Matthew 22 records the final public confrontations of Jesus before His arrest. He concludes His parables of judgment with the Wedding Feast (vv.1-14), then is tested by four hostile groups: Herodians on tribute (vv.15-22), Sadducees on resurrection (vv.23-33), a Pharisee lawyer on the greatest commandment (vv.34-40), and finally Jesus turns the tables and silences them all with the question of David''s Lord (vv.41-46). Each adversary is reduced to silence, demonstrating that all earthly authority and human reasoning collapse before the wisdom of the Messiah.',
  'The King Above Every Question',
  'πειράζω',
  'To test, tempt, examine — used of the adversaries who came not to learn but to entrap (Mt 22:18, 35). The chapter is a study in the failure of every test brought against Christ, and the silencing of every opposing voice (v.46).',
  '["1-14 The parable of the wedding feast — invitation, refusal, judgment, the unrobed guest", "15-22 The question of tribute to Caesar — Pharisees and Herodians", "23-33 The question of resurrection — Sadducees and the seven brothers", "34-40 The question of the greatest commandment — the lawyer", "41-46 The question of David''s Lord — Christ silences all"]'::jsonb
FROM books b WHERE b.name = 'Matthew'
ON CONFLICT (book_id, chapter_number) DO UPDATE SET
  theme = EXCLUDED.theme,
  overview = EXCLUDED.overview,
  key_word_original = EXCLUDED.key_word_original,
  key_word_meaning = EXCLUDED.key_word_meaning,
  outline = EXCLUDED.outline;

-- =====================================================================
-- 2. VERSES (1-46)
-- =====================================================================
INSERT INTO verses (chapter_id, verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
SELECT c.id, v.verse_number, v.kjv_text, v.original_text, v.transliteration, v.study_note, v.doctrinal_note
FROM chapters c
JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (1, 'And Jesus answered and spake unto them again by parables, and said,',
   'Καὶ ἀποκριθεὶς ὁ Ἰησοῦς πάλιν εἶπεν ἐν παραβολαῖς αὐτοῖς λέγων',
   'Kai apokritheis ho Iēsous palin eipen en parabolais autois legōn',
   '"Answered" continues the Sanhedrin confrontation of ch. 21. The third parable in the trilogy of judgment (Two Sons, Wicked Husbandmen, Wedding Feast).',
   'God''s revelation comes in pressing waves. Christ multiplies parables not to entertain but to expose, giving repeated opportunities for repentance before judgment falls.'),
  (2, 'The kingdom of heaven is like unto a certain king, which made a marriage for his son,',
   'Ὡμοιώθη ἡ βασιλεία τῶν οὐρανῶν ἀνθρώπῳ βασιλεῖ, ὅστις ἐποίησεν γάμους τῷ υἱῷ αὐτοῦ',
   'Hōmoiōthē hē basileia tōn ouranōn anthrōpō basilei, hostis epoiēsen gamous tō hyiō autou',
   'God is the King; the Son is Christ; the wedding feast is the consummation of redemption (Rev 19:7-9). Marriage imagery for God''s relation to His people pervades Scripture (Hos 2:19; Isa 62:5; Eph 5:32).',
   'The gospel is announced in the imagery of a royal wedding. Salvation is not mere transaction but covenantal union, the Bridegroom-King receiving His bride.'),
  (3, 'And sent forth his servants to call them that were bidden to the wedding: and they would not come.',
   'καὶ ἀπέστειλεν τοὺς δούλους αὐτοῦ καλέσαι τοὺς κεκλημένους εἰς τοὺς γάμους, καὶ οὐκ ἤθελον ἐλθεῖν',
   'kai apesteilen tous doulous autou kalesai tous keklēmenous eis tous gamous, kai ouk ēthelon elthein',
   'In ancient near-eastern custom a first invitation was sent in advance, then a second summons announced the meal was ready. The first sending = OT prophets calling Israel to be ready for Messiah''s arrival.',
   'Refusal of the gospel is essentially a refusal of the will: "they would not." Unbelief is not lack of evidence but resistance of will.'),
  (4, 'Again, he sent forth other servants, saying, Tell them which are bidden, Behold, I have prepared my dinner: my oxen and my fatlings are killed, and all things are ready: come unto the marriage.',
   'πάλιν ἀπέστειλεν ἄλλους δούλους λέγων· Εἴπατε τοῖς κεκλημένοις· Ἰδοὺ τὸ ἄριστόν μου ἡτοίμακα, οἱ ταῦροί μου καὶ τὰ σιτιστὰ τεθυμένα, καὶ πάντα ἕτοιμα· δεῦτε εἰς τοὺς γάμους',
   'palin apesteilen allous doulous legōn: Eipate tois keklēmenois: Idou to ariston mou hētoimaka, hoi tauroi mou kai ta sitista tethymena, kai panta hetoima: deute eis tous gamous',
   '"All things are ready" — the second sending corresponds to the apostolic preaching after the cross: salvation accomplished, the feast spread, only acceptance required.',
   'The gospel announces a finished work: "It is ready." Nothing more must be added by the sinner; only come and receive what God has prepared at infinite cost.'),
  (5, 'But they made light of it, and went their ways, one to his farm, another to his merchandise:',
   'οἱ δὲ ἀμελήσαντες ἀπῆλθον, ὁ μὲν εἰς τὸν ἴδιον ἀγρόν, ὁ δὲ ἐπὶ τὴν ἐμπορίαν αὐτοῦ',
   'hoi de amelēsantes apēlthon, ho men eis ton idion agron, ho de epi tēn emporian autou',
   '"Made light" (amelēsantes) = treated as unimportant, neglected. The deadliest sin against the gospel is not active opposition but bored indifference — preferring the trivial to the eternal.',
   'Most who perish do so not by violent rejection but by quiet preference of farm and trade above the King''s feast. Hell is paved with intentions to attend later.'),
  (6, 'And the remnant took his servants, and entreated them spitefully, and slew them.',
   'οἱ δὲ λοιποὶ κρατήσαντες τοὺς δούλους αὐτοῦ ὕβρισαν καὶ ἀπέκτειναν',
   'hoi de loipoi kratēsantes tous doulous autou hybrisan kai apekteinan',
   'The fulfillment was the persecution of the apostolic church (Stephen, James, the believers scattered, Acts 7-12). Persistent gospel proclamation provokes persistent rage.',
   'Where the gospel is rejected, the messengers will eventually be hated. The world that crucified the Master will not spare the servants (Jn 15:20).'),
  (7, 'But when the king heard thereof, he was wroth: and he sent forth his armies, and destroyed those murderers, and burned up their city.',
   'ὁ δὲ βασιλεὺς ὠργίσθη, καὶ πέμψας τὰ στρατεύματα αὐτοῦ ἀπώλεσεν τοὺς φονεῖς ἐκείνους καὶ τὴν πόλιν αὐτῶν ἐνέπρησεν',
   'ho de basileus ōrgisthē, kai pempsas ta strateumata autou apōlesen tous phoneis ekeinous kai tēn polin autōn eneprēsen',
   'A precise prophecy of Jerusalem''s destruction by Roman armies in AD 70, fulfilled within a generation. Even pagan armies are God''s instruments to execute covenant judgment (cf. Hab 1:6; Isa 10:5).',
   'God''s patience has limits; rejection of His Son issues in temporal and eternal judgment. The Roman armies were "His armies" because all kings are stewards of His purposes.'),
  (8, 'Then saith he to his servants, The wedding is ready, but they which were bidden were not worthy.',
   'τότε λέγει τοῖς δούλοις αὐτοῦ· Ὁ μὲν γάμος ἕτοιμός ἐστιν, οἱ δὲ κεκλημένοι οὐκ ἦσαν ἄξιοι',
   'tote legei tois doulois autou: Ho men gamos hetoimos estin, hoi de keklēmenoi ouk ēsan axioi',
   '"Not worthy" — not because they were less worthy by nature than others, but because they refused. Worthiness in the kingdom is not status but response to grace.',
   'No one is worthy by works (Rom 3:23); the worthy are those who come at God''s call. Rejection forfeits worthiness; acceptance constitutes worthiness in Christ.'),
  (9, 'Go ye therefore into the highways, and as many as ye shall find, bid to the marriage.',
   'πορεύεσθε οὖν ἐπὶ τὰς διεξόδους τῶν ὁδῶν, καὶ ὅσους ἐὰν εὕρητε καλέσατε εἰς τοὺς γάμους',
   'poreuesthe oun epi tas diexodous tōn hodōn, kai hosous ean heurēte kalesate eis tous gamous',
   '"Highways" (diexodous, "thoroughfares, exits of the streets") — the wider Gentile world. The Great Commission is foreshadowed: when Israel''s leaders reject, the gospel goes to all nations.',
   'God will have a full house at His Son''s wedding. Election does not fail; if some refuse, the call extends until the elect from every nation are gathered.'),
  (10, 'So those servants went out into the highways, and gathered together all as many as they found, both bad and good: and the wedding was furnished with guests.',
   'καὶ ἐξελθόντες οἱ δοῦλοι ἐκεῖνοι εἰς τὰς ὁδοὺς συνήγαγον πάντας οὓς εὗρον, πονηρούς τε καὶ ἀγαθούς· καὶ ἐπλήσθη ὁ γάμος ἀνακειμένων',
   'kai exelthontes hoi douloi ekeinoi eis tas hodous synēgagon pantas hous heuron, ponērous te kai agathous: kai eplēsthē ho gamos anakeimenōn',
   '"Bad and good" — the visible Church contains both wheat and tares (Mt 13:24-30, 47-50). The mixed gathering is real but not final; the king will inspect.',
   'Outward inclusion in the Church is not yet personal salvation. The gospel reaches all kinds; the King will distinguish the genuine in due time.'),
  (11, 'And when the king came in to see the guests, he saw there a man which had not on a wedding garment:',
   'εἰσελθὼν δὲ ὁ βασιλεὺς θεάσασθαι τοὺς ἀνακειμένους εἶδεν ἐκεῖ ἄνθρωπον οὐκ ἐνδεδυμένον ἔνδυμα γάμου',
   'eiselthōn de ho basileus theasasthai tous anakeimenous eiden ekei anthrōpon ouk endedymenon endyma gamou',
   'In Eastern royal feasts the host customarily provided wedding robes to all guests (cf. Gen 45:22; 2 Kgs 10:22). To refuse the offered robe was deliberate insult.',
   'God provides the righteousness His feast requires (Isa 61:10; Rev 19:8). To attempt to enter clothed in our own merit is a deliberate rejection of the King''s provided righteousness.'),
  (12, 'And he saith unto him, Friend, how camest thou in hither not having a wedding garment? And he was speechless.',
   'καὶ λέγει αὐτῷ· Ἑταῖρε, πῶς εἰσῆλθες ὧδε μὴ ἔχων ἔνδυμα γάμου; ὁ δὲ ἐφιμώθη',
   'kai legei autō: Hetaire, pōs eisēlthes hōde mē echōn endyma gamou? ho de ephimōthē',
   '"Friend" (hetaire) is a cool address (cf. Mt 20:13; 26:50 — Judas at the betrayal). "Speechless" (ephimōthē) is the silencing of one with no defense, anticipating Romans 3:19.',
   'On judgment day every mouth will be stopped (Rom 3:19). Self-righteousness has no answer when face to face with the King who sees through every disguise.'),
  (13, 'Then said the king to the servants, Bind him hand and foot, and take him away, and cast him into outer darkness; there shall be weeping and gnashing of teeth.',
   'τότε εἶπεν ὁ βασιλεὺς τοῖς διακόνοις· Δήσαντες αὐτοῦ πόδας καὶ χεῖρας ἐκβάλετε αὐτὸν εἰς τὸ σκότος τὸ ἐξώτερον· ἐκεῖ ἔσται ὁ κλαυθμὸς καὶ ὁ βρυγμὸς τῶν ὀδόντων',
   'tote eipen ho basileus tois diakonois: Dēsantes autou podas kai cheiras ekbalete auton eis to skotos to exōteron: ekei estai ho klauthmos kai ho brygmos tōn odontōn',
   '"Outer darkness" with "weeping and gnashing" — Matthew''s recurring description of final judgment (8:12; 13:42, 50; 25:30). Outside the lit hall of the feast lies the eternal night.',
   'Hell is exclusion from the joy of the Bridegroom''s feast. The torment is conscious (weeping = anguish; gnashing = rage), endless, and final.'),
  (14, 'For many are called, but few are chosen.',
   'πολλοὶ γάρ εἰσιν κλητοί, ὀλίγοι δὲ ἐκλεκτοί',
   'polloi gar eisin klētoi, oligoi de eklektoi',
   'The summary of the parable. The general call goes to many through the gospel; the effective election by which one actually accepts and is clothed in Christ''s righteousness is from God alone.',
   'External invitation is wide; saving response is by sovereign grace. The contrast warns against presumption and drives the hearer to seek the wedding garment of imputed righteousness.'),
  (15, 'Then went the Pharisees, and took counsel how they might entangle him in his talk.',
   'Τότε πορευθέντες οἱ Φαρισαῖοι συμβούλιον ἔλαβον ὅπως αὐτὸν παγιδεύσωσιν ἐν λόγῳ',
   'Tote poreuthentes hoi Pharisaioi symboulion elabon hopōs auton pagideusōsin en logō',
   '"Entangle / ensnare" (pagideusōsin) — to catch in a trap. The opposition shifts from physical seizure (21:46) to verbal entrapment when force fails.',
   'Where men cannot defeat Christ by force, they attempt by sophistry. Both methods fail. The wisdom of God shatters the wisdom of the world (1 Cor 1:25).'),
  (16, 'And they sent out unto him their disciples with the Herodians, saying, Master, we know that thou art true, and teachest the way of God in truth, neither carest thou for any man: for thou regardest not the person of men.',
   'καὶ ἀποστέλλουσιν αὐτῷ τοὺς μαθητὰς αὐτῶν μετὰ τῶν Ἡρῳδιανῶν λέγοντες· Διδάσκαλε, οἴδαμεν ὅτι ἀληθὴς εἶ καὶ τὴν ὁδὸν τοῦ Θεοῦ ἐν ἀληθείᾳ διδάσκεις, καὶ οὐ μέλει σοι περὶ οὐδενός, οὐ γὰρ βλέπεις εἰς πρόσωπον ἀνθρώπων',
   'kai apostellousin autō tous mathētas autōn meta tōn Hērōdianōn legontes: Didaskale, oidamen hoti alēthēs ei kai tēn hodon tou Theou en alētheia didaskeis, kai ou melei soi peri oudenos, ou gar blepeis eis prosōpon anthrōpōn',
   'Pharisees (anti-Roman) and Herodians (pro-Roman) — natural enemies united against Jesus. Their flattery is a trap; they hope to provoke an answer that offends one party or the other.',
   'False compliments often disguise hostile motives. Christ''s impartiality is true ("you do not regard the face of men") even when proclaimed insincerely.'),
  (17, 'Tell us therefore, What thinkest thou? Is it lawful to give tribute unto Caesar, or not?',
   'εἰπὸν οὖν ἡμῖν, τί σοι δοκεῖ; ἔξεστιν δοῦναι κῆνσον Καίσαρι ἢ οὔ',
   'eipon oun hēmin, ti soi dokei? exestin dounai kēnson Kaisari ē ou',
   'The kēnsos was the Roman head-tax of one denarius per adult. Saying "yes" would alienate the Jewish populace; saying "no" would be sedition reportable to Pilate.',
   'Every "either-or" trap that men devise against Christ collapses before the third path of divine wisdom. There is no contradiction the Lord cannot transcend.'),
  (18, 'But Jesus perceived their wickedness, and said, Why tempt ye me, ye hypocrites?',
   'γνοὺς δὲ ὁ Ἰησοῦς τὴν πονηρίαν αὐτῶν εἶπεν· Τί με πειράζετε, ὑποκριταί',
   'gnous de ho Iēsous tēn ponērian autōn eipen: Ti me peirazete, hypokritai',
   '"Perceived" — Jesus reads the heart (Jn 2:25). "Hypocrites" (hypokritai) = stage actors. Their flattery and question are theater designed for an entrapment scene.',
   'Christ''s omniscience pierces all masks. The Lord who weighs hearts cannot be deceived by political performance.'),
  (19, 'Shew me the tribute money. And they brought unto him a penny.',
   'ἐπιδείξατέ μοι τὸ νόμισμα τοῦ κήνσου. οἱ δὲ προσήνεγκαν αὐτῷ δηνάριον',
   'epideixate moi to nomisma tou kēnsou. hoi de prosēnenkan autō dēnarion',
   'Jesus has no Roman coin on Him in the temple courts; they produce one — exposing that they themselves use Caesar''s currency. Their own pocket has answered before His tongue.',
   'Often the simplest demonstration of evidence undoes elaborate trap. Christ''s wisdom is not loud but devastating.'),
  (20, 'And he saith unto them, Whose is this image and superscription?',
   'καὶ λέγει αὐτοῖς· Τίνος ἡ εἰκὼν αὕτη καὶ ἡ ἐπιγραφή',
   'kai legei autois: Tinos hē eikōn hautē kai hē epigraphē',
   'The denarius bore Tiberius'' image with the inscription "Tiberius Caesar Augustus, son of the divine Augustus." For strict Jews this was idolatrous; yet they carried it.',
   'The image on the coin determines its allegiance. The image of God on man (Gen 1:27) determines our deeper allegiance — to God Himself.'),
  (21, 'They say unto him, Caesar''s. Then saith he unto them, Render therefore unto Caesar the things which are Caesar''s; and unto God the things that are God''s.',
   'λέγουσιν· Καίσαρος. τότε λέγει αὐτοῖς· Ἀπόδοτε οὖν τὰ Καίσαρος Καίσαρι καὶ τὰ τοῦ Θεοῦ τῷ Θεῷ',
   'legousin: Kaisaros. tote legei autois: Apodote oun ta Kaisaros Kaisari kai ta tou Theou tō Theō',
   '"Render" (apodote) = give back what is owed. The coin bears Caesar''s image — give it back to him. Man bears God''s image — give him back to God. Civil obedience and ultimate worship are not in conflict but in proper order.',
   'Foundational doctrine of two kingdoms. Christians owe legitimate civil obedience (Rom 13) but their souls bear God''s image and belong to Him alone. When Caesar demands what is God''s, God must be obeyed (Acts 5:29).'),
  (22, 'When they had heard these words, they marvelled, and left him, and went their way.',
   'καὶ ἀκούσαντες ἐθαύμασαν, καὶ ἀφέντες αὐτὸν ἀπῆλθαν',
   'kai akousantes ethaumasan, kai aphentes auton apēlthan',
   'Astonishment (ethaumasan) but not repentance. They marveled at the answer yet remained His enemies. Wonder without worship is the tragedy of the merely impressed.',
   'Many will admire Christ as a teacher who refuse Him as Lord. Marvel that does not bow soon turns to murder.'),
  (23, 'The same day came to him the Sadducees, which say that there is no resurrection, and asked him,',
   'Ἐν ἐκείνῃ τῇ ἡμέρᾳ προσῆλθον αὐτῷ Σαδδουκαῖοι, λέγοντες μὴ εἶναι ἀνάστασιν, καὶ ἐπηρώτησαν αὐτὸν',
   'En ekeinē tē hēmera prosēlthon autō Saddoukaioi, legontes mē einai anastasin, kai epērōtēsan auton',
   'Sadducees were the priestly aristocracy controlling the temple. They accepted only the Pentateuch as fully binding and rejected resurrection, angels, spirits (Acts 23:8). Their question is a hypothetical reductio ad absurdum.',
   'Theological liberalism in any age trims revelation to the comfortable and ridicules supernatural truth. The Sadducees of Jesus'' day differ only in dress from rationalists in every century.'),
  (24, 'Saying, Master, Moses said, If a man die, having no children, his brother shall marry his wife, and raise up seed unto his brother.',
   'λέγοντες· Διδάσκαλε, Μωϋσῆς εἶπεν· Ἐάν τις ἀποθάνῃ μὴ ἔχων τέκνα, ἐπιγαμβρεύσει ὁ ἀδελφὸς αὐτοῦ τὴν γυναῖκα αὐτοῦ καὶ ἀναστήσει σπέρμα τῷ ἀδελφῷ αὐτοῦ',
   'legontes: Didaskale, Mōusēs eipen: Ean tis apothanē mē echōn tekna, epigambreusei ho adelphos autou tēn gynaika autou kai anastēsei sperma tō adelphō autou',
   'The law of levirate marriage (Deut 25:5-10), designed to preserve a dead brother''s name and inheritance line. The Sadducees use it to construct an absurd scenario.',
   'Treating Scripture as a tool to mock truth is a dangerous game. The Sadducees twist a compassionate law into a weapon against resurrection.'),
  (25, 'Now there were with us seven brethren: and the first, when he had married a wife, deceased, and, having no issue, left his wife unto his brother:',
   'ἦσαν δὲ παρ᾽ ἡμῖν ἑπτὰ ἀδελφοί· καὶ ὁ πρῶτος γήμας ἐτελεύτησεν, καὶ μὴ ἔχων σπέρμα ἀφῆκεν τὴν γυναῖκα αὐτοῦ τῷ ἀδελφῷ αὐτοῦ',
   'ēsan de par'' hēmin hepta adelphoi: kai ho prōtos gēmas eteleutēsen, kai mē echōn sperma aphēken tēn gynaika autou tō adelphō autou',
   'Seven brothers — perhaps borrowed from the apocryphal book of Tobit (3:8; 6:14) where the demon Asmodeus killed seven husbands of Sarah. The number is rhetorically extreme.',
   'False arguments often pile up vivid extremes to obscure the simple truth. The Sadducees stack improbable scenarios to discredit a clear doctrine.'),
  (26, 'Likewise the second also, and the third, unto the seventh.',
   'ὁμοίως καὶ ὁ δεύτερος καὶ ὁ τρίτος, ἕως τῶν ἑπτά',
   'homoiōs kai ho deuteros kai ho tritos, heōs tōn hepta',
   'The repetition reinforces the supposed dilemma. The story is constructed to corner Jesus into apparently endorsing celestial polyandry.',
   'Skepticism often dresses itself in elaborate hypotheticals. Jesus will dismantle not the example but the whole framework behind it.'),
  (27, 'And last of all the woman died also.',
   'ὕστερον δὲ πάντων ἀπέθανεν ἡ γυνή',
   'hysteron de pantōn apethanen hē gynē',
   'The whole question turns on which of the seven would have her in the resurrection — assuming earthly marriage continues hereafter.',
   'The Sadducees'' error rests on a false premise about the nature of resurrection life. Bad questions arise from bad assumptions.'),
  (28, 'Therefore in the resurrection whose wife shall she be of the seven? for they all had her.',
   'ἐν τῇ ἀναστάσει οὖν τίνος τῶν ἑπτὰ ἔσται γυνή; πάντες γὰρ ἔσχον αὐτήν',
   'en tē anastasei oun tinos tōn hepta estai gynē? pantes gar eschon autēn',
   'A reductio ad absurdum: if resurrection is true, then heavenly chaos. The Sadducees expect Jesus either to abandon resurrection or to give a foolish answer.',
   'Smug skepticism imagines it has cornered orthodoxy until orthodoxy reveals categories the skeptic has not even considered.'),
  (29, 'Jesus answered and said unto them, Ye do err, not knowing the scriptures, nor the power of God.',
   'ἀποκριθεὶς δὲ ὁ Ἰησοῦς εἶπεν αὐτοῖς· Πλανᾶσθε μὴ εἰδότες τὰς γραφὰς μηδὲ τὴν δύναμιν τοῦ Θεοῦ',
   'apokritheis de ho Iēsous eipen autois: Planasthe mē eidotes tas graphas mēde tēn dynamin tou Theou',
   '"Ye err" (planasthe) = wander astray. Two roots of error: ignorance of Scripture (theological deficiency) and ignorance of God''s power (limited expectations of what He can do).',
   'Sound doctrine requires both Scripture (the content of revelation) and an awareness of God''s power (the scale of His action). Reductionism in either direction breeds heresy.'),
  (30, 'For in the resurrection they neither marry, nor are given in marriage, but are as the angels of God in heaven.',
   'ἐν γὰρ τῇ ἀναστάσει οὔτε γαμοῦσιν οὔτε γαμίζονται, ἀλλ᾽ ὡς ἄγγελοι Θεοῦ ἐν οὐρανῷ εἰσιν',
   'en gar tē anastasei oute gamousin oute gamizontai, all'' hōs angeloi Theou en ouranō eisin',
   'Marriage belongs to this age, partly for procreation. In the resurrection no death means no need for marital reproduction. "As the angels" — not bodiless, but immortal and unmarried.',
   'Resurrection life transcends, not abolishes, earthly relations. Earthly bonds find their perfection in the unmediated communion of all saints with Christ the Bridegroom.'),
  (31, 'But as touching the resurrection of the dead, have ye not read that which was spoken unto you by God, saying,',
   'περὶ δὲ τῆς ἀναστάσεως τῶν νεκρῶν οὐκ ἀνέγνωτε τὸ ῥηθὲν ὑμῖν ὑπὸ τοῦ Θεοῦ λέγοντος',
   'peri de tēs anastaseōs tōn nekrōn ouk anegnōte to rhēthen hymin hypo tou Theou legontos',
   'Jesus argues from the Pentateuch (the only fully authoritative books for Sadducees) — meeting them on their own canon. The choice of Exodus 3 is strategic.',
   'Christ shows the doctrine of resurrection in the very part of Scripture His opponents revere. Solid biblical teaching meets each audience where it stands.'),
  (32, 'I am the God of Abraham, and the God of Isaac, and the God of Jacob? God is not the God of the dead, but of the living.',
   'Ἐγώ εἰμι ὁ Θεὸς Ἀβραὰμ καὶ ὁ Θεὸς Ἰσαὰκ καὶ ὁ Θεὸς Ἰακώβ; οὐκ ἔστιν ὁ Θεὸς νεκρῶν ἀλλὰ ζώντων',
   'Egō eimi ho Theos Abraam kai ho Theos Isaak kai ho Theos Iakōb? ouk estin ho Theos nekrōn alla zōntōn',
   'Quotes Exodus 3:6. The argument: God spoke to Moses (centuries after the patriarchs) as still being their God. Therefore the patriarchs must still live in some real sense, awaiting bodily resurrection.',
   'God''s covenant with His people is unbreakable, not even by death. To be in covenant with the living God is to share His life. Resurrection is built into the nature of the covenant.'),
  (33, 'And when the multitude heard this, they were astonished at his doctrine.',
   'καὶ ἀκούσαντες οἱ ὄχλοι ἐξεπλήσσοντο ἐπὶ τῇ διδαχῇ αὐτοῦ',
   'kai akousantes hoi ochloi exeplēssonto epi tē didachē autou',
   'The crowds were amazed (exeplēssonto, "struck out of themselves" — same word as Mt 7:28). Christ''s teaching combined Scripture mastery with theological depth.',
   'When the Word is rightly opened, hearts are astonished. The crowds recognized in Jesus an authority their teachers lacked.'),
  (34, 'But when the Pharisees had heard that he had put the Sadducees to silence, they were gathered together.',
   'Οἱ δὲ Φαρισαῖοι ἀκούσαντες ὅτι ἐφίμωσεν τοὺς Σαδδουκαίους συνήχθησαν ἐπὶ τὸ αὐτό',
   'Hoi de Pharisaioi akousantes hoti ephimōsen tous Saddoukaious synēchthēsan epi to auto',
   '"Put to silence" (ephimōsen) = literally "muzzled." The Pharisees, gloating their rivals'' defeat, now regroup for their own attempt — but they too will be silenced (v.46).',
   'Common opposition to Christ unites otherwise hostile parties. Yet none who oppose Him ultimately stand. Psalm 2:2-4 plays out in Jerusalem.'),
  (35, 'Then one of them, which was a lawyer, asked him a question, tempting him, and saying,',
   'καὶ ἐπηρώτησεν εἷς ἐξ αὐτῶν νομικὸς πειράζων αὐτὸν',
   'kai epērōtēsen heis ex autōn nomikos peirazōn auton',
   'A nomikos was a Torah expert. "Tempting" (peirazōn) signals hostile intent, though Mark records this lawyer was thoughtful and ended commended (Mk 12:34).',
   'Even hostile motives are subject to God''s grace. The same encounter that traps the proud may convert the curious.'),
  (36, 'Master, which is the great commandment in the law?',
   'Διδάσκαλε, ποία ἐντολὴ μεγάλη ἐν τῷ νόμῳ',
   'Didaskale, poia entolē megalē en tō nomō',
   'Rabbinic schools debated whether the 613 commandments could be reduced or ranked. The question was a test of theological priorities.',
   'The Bible''s many commands are not flat; they have structure and weight. To know which is greatest is to know God''s heart.'),
  (37, 'Jesus said unto him, Thou shalt love the Lord thy God with all thy heart, and with all thy soul, and with all thy mind.',
   'ὁ δὲ ἔφη αὐτῷ· Ἀγαπήσεις Κύριον τὸν Θεόν σου ἐν ὅλῃ τῇ καρδίᾳ σου καὶ ἐν ὅλῃ τῇ ψυχῇ σου καὶ ἐν ὅλῃ τῇ διανοίᾳ σου',
   'ho de ephē autō: Agapēseis Kyrion ton Theon sou en holē tē kardia sou kai en holē tē psychē sou kai en holē tē dianoia sou',
   'Quotes Deuteronomy 6:5 (the Shema), the daily confession of every devout Jew. Heart, soul, mind = the totality of human personhood.',
   'God demands total love — not merely external obedience but the integrated devotion of the whole inner being. The first commandment exposes the impossibility of self-righteousness.'),
  (38, 'This is the first and great commandment.',
   'αὕτη ἐστὶν ἡ μεγάλη καὶ πρώτη ἐντολή',
   'hautē estin hē megalē kai prōtē entolē',
   'First in priority and greatest in scope. Every other duty is derivative. Where this is missing, no other obedience is acceptable to God.',
   'Religion that lacks all-consuming love for God, however moral or industrious, is misdirected at its root. Love is the foundation, not the supplement, of obedience.'),
  (39, 'And the second is like unto it, Thou shalt love thy neighbour as thyself.',
   'δευτέρα δὲ ὁμοία αὐτῇ· Ἀγαπήσεις τὸν πλησίον σου ὡς σεαυτόν',
   'deutera de homoia autē: Agapēseis ton plēsion sou hōs seauton',
   'Quotes Leviticus 19:18, drawing it up from its near-burial in the holiness code to set it as the second pillar. "Like" (homoia) — same nature, flowing from love for God.',
   'Love for neighbor is not optional supplement to love for God; it is its inseparable expression (1 Jn 4:20). The two great commands are two aspects of one integrated love.'),
  (40, 'On these two commandments hang all the law and the prophets.',
   'ἐν ταύταις ταῖς δυσὶν ἐντολαῖς ὅλος ὁ νόμος κρέμαται καὶ οἱ προφῆται',
   'en tautais tais dysin entolais holos ho nomos krematai kai hoi prophētai',
   '"Hang" (krematai) like a door on its hinges or a body on its skeleton. Without these two loves, all the rest of Scripture loses its support.',
   'The whole Old Testament is unified by love. Every law, every prophecy, every commandment is an application of God''s call to love Him supremely and our neighbor truly.'),
  (41, 'While the Pharisees were gathered together, Jesus asked them,',
   'Συνηγμένων δὲ τῶν Φαρισαίων ἐπηρώτησεν αὐτοὺς ὁ Ἰησοῦς',
   'Synēgmenōn de tōn Pharisaiōn epērōtēsen autous ho Iēsous',
   'Jesus turns from defendant to inquisitor. Having silenced their attacks, He now poses the question that exposes the inadequacy of their Christology.',
   'The Lord who answered every question can also ask the question that none can answer. The crucial question is not what we think about life, but what we think of Christ.'),
  (42, 'Saying, What think ye of Christ? whose son is he? They say unto him, The son of David.',
   'λέγων· Τί ὑμῖν δοκεῖ περὶ τοῦ Χριστοῦ; τίνος υἱός ἐστιν; λέγουσιν αὐτῷ· Τοῦ Δαυίδ',
   'legōn: Ti hymin dokei peri tou Christou? tinos hyios estin? legousin autō: Tou David',
   '"What think ye of Christ?" — the most important question any soul will ever face. The Pharisees answer correctly but partially: Son of David. They miss that He is also Son of God.',
   'A merely human Messiah cannot save. Christ must be fully Davidic (truly man, qualified to redeem) and fully divine (with power to redeem). Jesus exposes the gap in their theology.'),
  (43, 'He saith unto them, How then doth David in spirit call him Lord, saying,',
   'λέγει αὐτοῖς· Πῶς οὖν Δαυὶδ ἐν Πνεύματι καλεῖ αὐτὸν Κύριον λέγων',
   'legei autois: Pōs oun David en Pneumati kalei auton Kyrion legōn',
   '"In spirit" — that is, by the Holy Spirit''s inspiration. Jesus affirms the inerrant inspiration of David''s words in Psalm 110.',
   'Christ Himself testifies to the Spirit-breathed authority of OT Scripture. To deny biblical inspiration is to deny the testimony of the Lord Himself.'),
  (44, 'The LORD said unto my Lord, Sit thou on my right hand, till I make thine enemies thy footstool?',
   'Εἶπεν Κύριος τῷ Κυρίῳ μου· Κάθου ἐκ δεξιῶν μου ἕως ἂν θῶ τοὺς ἐχθρούς σου ὑποκάτω τῶν ποδῶν σου',
   'Eipen Kyrios tō Kyriō mou: Kathou ek dexiōn mou heōs an thō tous echthrous sou hypokatō tōn podōn sou',
   'Quotes Psalm 110:1 — the most quoted OT verse in the NT (cited 25+ times). David, by inspiration, calls his own descendant "Lord" (Adonai), affirming His divine status.',
   'The Messiah is both Son of David (true humanity) and Son of God (true deity). Psalm 110 establishes the eternal session of Christ at the Father''s right hand, ruling until every enemy is subdued (1 Cor 15:25).'),
  (45, 'If David then call him Lord, how is he his son?',
   'εἰ οὖν Δαυὶδ καλεῖ αὐτὸν Κύριον, πῶς υἱὸς αὐτοῦ ἐστιν',
   'ei oun David kalei auton Kyrion, pōs hyios autou estin',
   'No mere descendant is greater than his ancestor. The Pharisees have no answer because the answer requires recognizing Christ as both human descendant and divine Lord — the very confession they refuse.',
   'The mystery of the incarnation is the resolution: Christ is David''s son according to the flesh and David''s Lord according to the Spirit (Rom 1:3-4).'),
  (46, 'And no man was able to answer him a word, neither durst any man from that day forth ask him any more questions.',
   'καὶ οὐδεὶς ἐδύνατο ἀποκριθῆναι αὐτῷ λόγον, οὐδὲ ἐτόλμησέν τις ἀπ᾽ ἐκείνης τῆς ἡμέρας ἐπερωτῆσαι αὐτὸν οὐκέτι',
   'kai oudeis edynato apokrithēnai autō logon, oude etolmēsen tis ap'' ekeinēs tēs hēmeras eperōtēsai auton ouketi',
   'Total verbal defeat of every adversary — Pharisees, Sadducees, Herodians, lawyers. The questioning ends; only the cross will speak from this point on.',
   'Christ silences the wisdom of the world. From this moment on the only "answer" His enemies could give was crucifixion. Argument exhausted, malice remained.')
) AS v(verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
WHERE b.name = 'Matthew' AND c.chapter_number = 22
ON CONFLICT (chapter_id, verse_number) DO UPDATE SET
  kjv_text = EXCLUDED.kjv_text,
  original_text = EXCLUDED.original_text,
  transliteration = EXCLUDED.transliteration,
  study_note = EXCLUDED.study_note,
  doctrinal_note = EXCLUDED.doctrinal_note;

-- =====================================================================
-- 3. WORD STUDIES
-- =====================================================================
INSERT INTO word_studies (verse_id, original_word, transliteration, strongs_number, meaning, word_order)
SELECT v.id, w.original_word, w.transliteration, w.strongs_number, w.meaning, w.word_order
FROM verses v
JOIN chapters c ON v.chapter_id = c.id
JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (2, 'γάμους', 'gamous', 'G1062', 'Wedding feast / marriage celebrations — plural form denotes the entire wedding festivities, often lasting seven days. The eschatological consummation of God and His people (Rev 19:7-9).', 1),
  (3, 'κεκλημένους', 'keklēmenous', 'G2564', 'Those having been called / invited — perfect passive participle denoting a standing invitation. Israel had been called from of old; the gospel summons makes the call effective.', 1),
  (5, 'ἀμελήσαντες', 'amelēsantes', 'G272', 'Made light of / disregarded / neglected — to be careless about, treat as unimportant. The same root as in Heb 2:3 ("how shall we escape if we neglect so great salvation").', 1),
  (7, 'ὠργίσθη', 'ōrgisthē', 'G3710', 'Was wroth — divine wrath roused, settled judicial anger against persistent rejection. Not capricious temper but the just response of holy love to scorn.', 1),
  (8, 'ἄξιοι', 'axioi', 'G514', 'Worthy — having balanced weight, fitting. In gospel context, worthiness is response to grace, not merit before grace. The unworthy who come are made worthy in Christ.', 1),
  (11, 'ἔνδυμα γάμου', 'endyma gamou', 'G1742/G1062', 'Wedding garment — likely a robe provided by the host. Symbol of the imputed righteousness of Christ (Isa 61:10; Rev 19:8) without which no one stands at the marriage of the Lamb.', 1),
  (12, 'ἑταῖρε', 'hetaire', 'G2083', 'Friend / comrade — a cool, formal address (cf. Mt 20:13; 26:50). Not the warm philos but a distancing term used at moments of judgment. Same word Jesus addresses Judas at the betrayal.', 1),
  (12, 'ἐφιμώθη', 'ephimōthē', 'G5392', 'Was speechless / muzzled — literally "had his mouth shut." Anticipates Romans 3:19 where every mouth is stopped before God.', 2),
  (13, 'σκότος ἐξώτερον', 'skotos exōteron', 'G4655/G1857', 'Outer darkness — Matthew''s recurring eschatological imagery (8:12; 13:42; 25:30). Beyond the lit hall of the King''s feast lies the eternal night of exclusion.', 1),
  (14, 'κλητοί / ἐκλεκτοί', 'klētoi / eklektoi', 'G2822/G1588', 'Called / chosen — distinct theological terms. The general gospel call (klētoi) goes to many; the effective electing call (eklektoi) is the sovereign work by which God''s chosen actually believe.', 1),
  (15, 'παγιδεύσωσιν', 'pagideusōsin', 'G3802', 'Entrap / ensnare — from pagis ("snare, trap"). The opposition shifts to verbal snares when violence proves impossible.', 1),
  (17, 'κῆνσον', 'kēnson', 'G2778', 'Tribute / census tax — the head-tax of one denarius levied on all subjects of Rome. A flashpoint of Jewish resentment, occasion of the Zealot revolt of AD 6 (Acts 5:37).', 1),
  (18, 'ὑποκριταί', 'hypokritai', 'G5273', 'Hypocrites — Greek theatrical term for actors who wore masks. The Pharisees'' flattery is stagecraft for entrapment. Christ pierces the mask.', 1),
  (19, 'δηνάριον', 'dēnarion', 'G1220', 'Denarius — Roman silver coin equal to a day''s wage for a laborer. Bore Tiberius'' image and inscription; their producing one in the temple shows they used the coinage they questioned.', 1),
  (20, 'εἰκών', 'eikōn', 'G1504', 'Image / likeness — same word used in Genesis 1:26-27 LXX for man made in God''s image. Profound subtext: as the coin bears Caesar''s image and is his, so man bears God''s image and belongs to God.', 1),
  (21, 'Ἀπόδοτε', 'Apodote', 'G591', 'Render / give back — not "give" (didōmi) but "pay back what is owed" (apo + didōmi). Both Caesar and God have prior claims; we are to return to each what is owed.', 1),
  (23, 'ἀνάστασις', 'anastasis', 'G386', 'Resurrection — literally "standing up again." The bodily raising of the dead, denied by Sadducees but central to the apostolic gospel (1 Cor 15).', 1),
  (29, 'Πλανᾶσθε', 'Planasthe', 'G4105', 'Ye err / are deceived / wander — to lead astray, go astray. Used in Revelation of the great deceiver. Theological error is not innocent ignorance but a wandering from the way.', 1),
  (29, 'δύναμιν', 'dynamin', 'G1411', 'Power — inherent ability, the capacity for mighty acts. Sadducean error stems from limited expectations of what God can do; sound theology trusts both God''s Word and God''s power.', 2),
  (30, 'γαμοῦσιν / γαμίζονται', 'gamousin / gamizontai', 'G1060/G1061', 'Marry / are given in marriage — the active form for men taking wives, the passive for women being given by their fathers. Both cease in resurrection life.', 1),
  (32, 'Θεὸς ζώντων', 'Theos zōntōn', 'G2316/G2198', 'God of the living — Christ''s argument: God identifies as still being the God of patriarchs centuries dead, therefore they live in some real sense awaiting the bodily resurrection. Covenant communion outlives bodily death.', 1),
  (37, 'ἀγαπήσεις', 'agapēseis', 'G25', 'Thou shalt love — future indicative used with imperatival force. Agapaō denotes a willed, devoted, self-giving love, not mere emotion. Love commanded must be of the will.', 1),
  (37, 'καρδίᾳ / ψυχῇ / διανοίᾳ', 'kardia / psychē / dianoia', 'G2588/G5590/G1271', 'Heart / soul / mind — the totality of human personhood. Heart = inner motivational core; soul = animating life; mind = rational understanding. God demands integrated devotion.', 2),
  (39, 'πλησίον', 'plēsion', 'G4139', 'Neighbor — literally "the one near." Defined broadly by Jesus in the Good Samaritan parable (Lk 10) as anyone whose need is presented to us.', 1),
  (40, 'κρέμαται', 'krematai', 'G2910', 'Hangs — to suspend, depend upon. The whole law and prophets hang on these two commandments like a structure on its supporting beams. Without love at the foundation, the rest cannot stand.', 1),
  (44, 'Κύριος', 'Kyrios', 'G2962', 'Lord — translates both Hebrew YHWH (the divine name) and Adonai (sovereign master). David, addressing his royal descendant as Adonai, confesses His superhuman dignity.', 1)
) AS w(verse_number, original_word, transliteration, strongs_number, meaning, word_order)
WHERE b.name = 'Matthew' AND c.chapter_number = 22 AND v.verse_number = w.verse_number
ON CONFLICT DO NOTHING;

